#!/usr/bin/env python3
"""Verify the self-signed certificate at /app/ssl/server.crt."""
import subprocess
import sys
import datetime

CERT = "/app/ssl/server.crt"


def run(args):
    return subprocess.run(
        ["openssl", "x509", "-in", CERT, "-noout"] + args,
        capture_output=True, text=True, check=True,
    ).stdout.strip()


def main():
    import os
    if not os.path.exists(CERT):
        print(f"Certificate not found: {CERT}")
        sys.exit(1)

    # Load / parse subject
    try:
        subject = run(["-subject"])
    except subprocess.CalledProcessError as e:
        print(f"Failed to load certificate: {e.stderr}")
        sys.exit(1)

    # Common Name
    cn = None
    for part in subject.replace("subject=", "").split(","):
        kv = part.strip()
        if kv.startswith("CN"):
            cn = kv.split("=", 1)[1].strip()
    print(f"Common Name: {cn}")

    # Expiration date in YYYY-MM-DD
    not_after = run(["-enddate"]).replace("notAfter=", "").strip()
    dt = datetime.datetime.strptime(not_after, "%b %d %H:%M:%S %Y %Z")
    print(f"Expiration Date: {dt.strftime('%Y-%m-%d')}")

    print("Certificate verification successful")


if __name__ == "__main__":
    main()
